var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"터미널에서 <color=#ffd34c>셰퍼드</color>라는 키워드를 검색했더니 여러 정보가 나왔어.","JPN":"ターミナルで<color=#ffd34c>シェパード</color>と検索したら色んな情報が出てきた。","ENG":"I used the terminal to search for the keyword <color=#ffd34c>Shepherd</color> and got a lot of search results.","TWN":"我在終端搜索了<color=#ffd34c>牧羊犬</color>這個關鍵字，發現了很多資訊。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우선, 셰퍼드란 이름은 실험체 하나를 지칭하는 게 아니야. 이 시설에서 진행되던 프로젝트의 명칭이지.","JPN":"まず、シェパードは実験体の名前ではない。この施設で行われていた実験プロジェクトの名称だ。","ENG":"First of all, the name \\"Shepherd\\" doesn't refer to a single test subject. It's actually the name of a project carried out in this facility.","TWN":"首先，Shepard——牧羊犬這個名字，指的並不是單一的某個實驗體，而是這個設施中正在進行的項目名稱，其寓意為牧羊人。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 셰퍼드라는 실험을 통해 침식체를 통제하려던 흔적이 남아있어.","JPN":"シェパードという実験によって侵食体をコントロールしようとしていた記録が残っている。","ENG":"There are traces of attempts to control C.O.s using the Shepherd experiment.","TWN":"從研究記載來看，似乎是想透過這個所謂的牧羊人計畫來控制侵蝕體。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>스프리건 인자</color>라는 신물질을 이용했고, 실제로도 어느 정도 효과가 있었던 모양이야.","JPN":"実験は<color=#ffd34c>スプリガン因子</color>という新物質を利用したものであり、実際、一定の成果を出していたようだ。","ENG":"They used this new substance called the <color=#ffd34c>Spriggan Factor</color>, and it appeared to be somewhat effective.","TWN":"他們使用了一種名為<color=#ffd34c>守護者因子</color>的新物質，似乎頗有成效。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하지만 이상하네요. 그런 굉장한 프로젝트의 산물을 왜 여기 남겨두고 간 걸까요?","JPN":"だとしたら、ちょっと変ですよね。そんなすごいプロジェクトの産物とも言えるあの子を、なんでここに置いて行ったんでしょうか？","ENG":"That's odd. Why would they just abandon the result of an amazing project in rubble?","TWN":"奇怪……那他們為什麼要把如此令人驚嘆的項目產物留在異界？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"실패작이라 판단하고 포기했거나, 당시엔 데려갈 여력조차 없는 상황이었겠지.","JPN":"失敗作と判断して放置したか、連れていけない状況だったのだろう。","ENG":"They either determined it was a failure, gave up, or didn't have the resources to take it with them.","TWN":"可能是被他們判斷為失敗品而放棄了，又或者他們當時根本沒有能力帶走她。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"너희 관리국에게 이 시설의 위치를 들킨 뒤로는 더더욱 빼내기 힘들었을 테고.","JPN":"あなたたち管理局にこの施設の所在がバレてしまってからは、より連れ出すのは難しい状況になっていたはずだ。","ENG":"Even more so if the Administration found out the location of this facility.","TWN":"特別是當管理局發現這個設施後，想要將其回收就更加困難了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아…!","JPN":"あ……！","ENG":"Ah...!","TWN":"啊……！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그럼 선발대가 가지고 있던 총이 북방합의체 것이었다는 건…","JPN":"じゃあ先発隊が北方合意体の銃を持っていたのは……","ENG":"Then that gun the advance party had was from the Northern Union–","TWN":"這麼說來，先遣隊的槍來自北方和議會……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리가 쫓는 상대가 셰퍼드를 노리는 북방합의체의 첩자일 가능성이 높다는 뜻이지.","JPN":"私たちの捜索相手はシェパードの回収が目的の北方合意体のスパイである可能性が高いな。","ENG":"It means that the person we're after is most likely a Northern Union spy who is after Shepherd.","TWN":"這表示我們正在追捕的人，很有可能是北方和議會派來尋找牧羊犬的間諜。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"리프터로 위장해서 관리국을 속이고 의뢰를 받아 내다니, 진짜라면 보통 내기가 아니네요.","JPN":"リフターと偽って、管理局を騙して依頼を受けるなんて。それが本当だったらただごとではないですね。","ENG":"Taking on the job by deceiving the Administration and disguising as a lifter... If it really is a spy, it's no ordinary one.","TWN":"偽裝成打撈人，瞞過管理局，接受委託，如果這是真的，可真是大費周章呢。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"엄청난 사건의 소용돌이 한복판에 뛰어든 기분이에요.","JPN":"とんでもない事件に首を突っ込んでしまった感じがします。","ENG":"I feel like I just jumped into the middle of a huge event.","TWN":"感覺被捲進了了不得的事情裡……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이동하자. 우리가 찾는 연구동이 여기서 멀지 않아.","JPN":"移動しよう。目的地の研究棟はここから近い。","ENG":"Let's get moving. The lab we're looking for should be close by.","TWN":"繼續前進吧。我們要找的研究大樓離這裡不遠。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"subtitle","speaker":null,"text":{"KOREA":"B동. 프로젝트 셰퍼드 연구시설.","JPN":"B棟。プロジェクト・シェパードの研究施設。","ENG":"B Wing. Project Shepard Lab Facility.","TWN":"B棟。牧羊人計畫研究設施。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이 왼쪽은 실험체 격리실이네요. 오른쪽으로 가면 실험체를 감시하는 모니터룸이 나오고요.","JPN":"左は実験体の隔離室ですね。右に進めば実験体を監視するモニタールームが出ます。","ENG":"The left side is the test subject quarantine room. And if you go to the right, there is a monitor room where you can watch over the test subjects.","TWN":"嗯……左邊是實驗體隔離室。往右走，就是監控室，平時用來觀察實驗體。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"격리실 쪽은 침식체가 다수 감지되고 있어. 들어가려면 각오를 해야 할 거야.","JPN":"隔離室からは侵食体が多数感知されている。突入するには覚悟がいるな。","ENG":"I'm detecting a lot of C.O.s in the quarantine room. We'd better prepare if we're gonna go in there.","TWN":"隔離室裡檢測到了大量的侵蝕體。如果要進去的話，必須做好一定的準備。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이터니움 실드 잔량도 이젠 여유롭지 않네요.","JPN":"エタニウムシールドの残量も、余裕がありませんね。","ENG":"My Eternium shield is also running low now.","TWN":"我的永恆之金盾剩餘能量不多了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"제가 왼쪽으로 갈게요. 스펜서는 모니터룸 카메라로 그 아이를 찾아봐 주세요.","JPN":"私が左に進みます。スペンサーさんはモニタールームのカメラを使ってその子を探してください。","ENG":"I'll go to the left. Spencer, you go to the monitor room and use the cameras to find that kid.","TWN":"我往左走。史賓瑟，你用監控室的攝影機找那孩子吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"알겠어. 부디 조심해.","JPN":"わかった、気をつけて。","ENG":"Okay. Stay safe.","TWN":"好的。務必小心。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};